// DSGVO-Compliance-Gate — JS-Spiegel von
// supabase/functions/_shared/outreach-gate.ts. Bei Schema-Änderung
// dort BEIDE Stellen anpassen (Single-Source bleibt die .ts-Datei).
// Erzeugt NUR Entwürfe für Kandidaten, die das Gate bestehen.

const FREEMAIL = new Set(['gmail.com','googlemail.com','outlook.com','hotmail.com','live.com','yahoo.com','yahoo.de','gmx.de','gmx.net','web.de','t-online.de','icloud.com','me.com','aol.com','proton.me','protonmail.com','mail.com','freenet.de','posteo.de']);
const OPT_OUT_FOOTER = 'Sie erhalten diese einmalige geschäftliche Information auf Basis unseres berechtigten Interesses (Art. 6 Abs. 1 lit. f DSGVO). Wenn Sie keine weiteren Nachrichten wünschen, antworten Sie mit \u201eSTOPP\u201c \u2014 wir löschen Ihre Daten dann umgehend.';

function gate(c) {
  const v = [];
  if (c.opt_out === true) v.push('OPT_OUT');
  if (!c.source_url || !String(c.source_url).trim()) v.push('MISSING_SOURCE');
  const email = (c.contact_email || '').trim();
  let businessEmail = false;
  if (email) {
    const at = email.lastIndexOf('@');
    const dom = at > 0 ? email.slice(at + 1).toLowerCase() : '';
    if (!dom) v.push('PERSONAL_EMAIL');
    else if (FREEMAIL.has(dom)) v.push('PERSONAL_EMAIL');
    else businessEmail = true;
  }
  const basis = c.legal_basis || 'legitimate_interest';
  if (basis === 'legitimate_interest' && !(c.legitimate_interest_note || '').trim()) v.push('MISSING_LEGITIMATE_INTEREST_NOTE');
  if (basis === 'consent' && !(c.consent_ref || '').trim()) v.push('MISSING_CONSENT_REF');
  if (!((c.domain || '').trim()) && !businessEmail) v.push('MISSING_BUSINESS_CONTEXT');
  return v;
}

const out = [];
for (const item of $input.all()) {
  const c = item.json || {};
  const violations = gate(c);
  if (violations.length === 0) {
    out.push({ json: {
      decision: 'allow',
      company_name: c.company_name,
      contact_email: c.contact_email,
      draft_subject: `Kurzer Hinweis zu DSGVO/Tracking auf ${c.domain || c.company_name}`,
      draft_body: `Guten Tag,\n\nbei einer automatisierten Prüfung von ${c.domain || c.company_name} sind uns mögliche DSGVO-Themen aufgefallen. Gern teilen wir den kostenlosen Kurz-Audit.\n\n${OPT_OUT_FOOTER}`,
      legal_basis: c.legal_basis || 'legitimate_interest',
      source_url: c.source_url || null
    }});
  } else {
    out.push({ json: { decision: 'block', company_name: c.company_name, violations } });
  }
}
return out;
